template<typename T>
inline bool is_equal(const T a, const T b){
	return a==b;
}

template<typename T>
void benchmark_func(T seed, T* g_data, long size, int workgroupsize, 
                    unsigned int elements_per_wi, unsigned int fusion_degree,
                    int compute_iter, bool block_strided) {
	const int blockSize = workgroupsize;
	const int stride = block_strided ? blockSize : (blockSize * omp_get_max_threads());
	const int big_stride = omp_get_max_threads() * blockSize * elements_per_wi;

	#pragma omp parallel for
	for(long idx_base = 0; idx_base < size; idx_base += blockSize * elements_per_wi * fusion_degree) {
		T tmps[elements_per_wi];

		for(unsigned int k = 0; k < fusion_degree; k++) {
			for(unsigned int j = 0; j < elements_per_wi; j++) {
				long idx = idx_base + j * stride + k * big_stride;
				if(idx < size) {
					tmps[j] = g_data[idx];

					for(int i = 0; i < compute_iter; i++) {
						tmps[j] = tmps[j] * tmps[j] + seed;
					}
				}
			}

			T sum = (T)0;
			for(unsigned int j = 0; j < elements_per_wi - 1; j += 2) {
				sum += tmps[j] * tmps[j+1];
			}

			if(is_equal(sum, (T)-1)) {
				long store_idx = idx_base + k * big_stride;
				if(store_idx < size)
					g_data[store_idx] = sum;
			}
		}
	}
}

double get_os_time() {
	struct timespec ts;
	clock_gettime(CLOCK_MONOTONIC, &ts);
	return ts.tv_sec + ts.tv_nsec / 1000000000.0;
}

template<typename T>
double run_benchmark_iteration(T seed, T* data, long size, int workgroupsize,
                               unsigned int elements_per_wi, unsigned int fusion_degree,
                               int compute_iter, bool block_strided, bool use_os_timer) {
	double start_time = use_os_timer ? get_os_time() : omp_get_wtime();

	benchmark_func<T>(seed, data, size, workgroupsize, elements_per_wi, 
                     fusion_degree, compute_iter, block_strided);

	double end_time = use_os_timer ? get_os_time() : omp_get_wtime();
	return end_time - start_time;
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              double* cbuffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer,
              bool block_strided) {
	const long compute_grid_size = size / elements_per_wi / fusion_degree;
	const int current_compute_iterations = compute_iterations[krn_idx];
	const long long computations =
		(elements_per_wi * (long long)compute_grid_size +
		(2 * elements_per_wi * current_compute_iterations) *
			(long long)compute_grid_size) *
		fusion_degree;
	const long long memoryoperations = size;

	constexpr auto total_bench_iterations = 3;

	double kernel_time_mad_sp = 0.0;
	for(int i = 0; i < total_bench_iterations; i++) {
		float* data_f = (float*)cbuffer;
		double t = run_benchmark_iteration<float>(1.0f, (float*)cbuffer, size, 
			workgroupsize, elements_per_wi, fusion_degree, 
			current_compute_iterations, block_strided, use_os_timer);
		if(i == 0 || t < kernel_time_mad_sp) kernel_time_mad_sp = t;
	}

	double kernel_time_mad_dp = 0.0;
	for(int i = 0; i < total_bench_iterations; i++) {
		double t = run_benchmark_iteration<double>(1.0, (double*)cbuffer, size, 
			workgroupsize, elements_per_wi, fusion_degree, 
			current_compute_iterations, block_strided, use_os_timer);
		if(i == 0 || t < kernel_time_mad_dp) kernel_time_mad_dp = t;
	}

	double kernel_time_mad_hp = 0.0;
	for(int i = 0; i < total_bench_iterations; i++) {
		short* data_h = (short*)cbuffer;
		double t = run_benchmark_iteration<short>(15360, (short*)cbuffer, size, 
			workgroupsize, elements_per_wi, fusion_degree, 
			current_compute_iterations, block_strided, use_os_timer);
		if(i == 0 || t < kernel_time_mad_hp) kernel_time_mad_hp = t;
	}

	double kernel_time_mad_int = 0.0;
	for(int i = 0; i < total_bench_iterations; i++) {
		int* data_i = (int*)cbuffer;
		double t = run_benchmark_iteration<int>(1, (int*)cbuffer, size, 
			workgroupsize, elements_per_wi, fusion_degree, 
			current_compute_iterations, block_strided, use_os_timer);
		if(i == 0 || t < kernel_time_mad_int) kernel_time_mad_int = t;
	}

	printf(
		"         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
		"%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
		current_compute_iterations,
		((double)computations) / ((double)memoryoperations * sizeof(float)),
		kernel_time_mad_sp,
		((double)computations) / kernel_time_mad_sp * 1000. /
			(double)(1000 * 1000 * 1000),
		((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
			(1000. * 1000. * 1000.),
		((double)computations) / ((double)memoryoperations * sizeof(double)),
		kernel_time_mad_dp,
		((double)computations) / kernel_time_mad_dp * 1000. /
			(double)(1000 * 1000 * 1000),
		((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
			(1000. * 1000. * 1000.),
		((double)2 * computations) /
			((double)memoryoperations * sizeof(short)),
		kernel_time_mad_hp,
		((double)2 * computations) / kernel_time_mad_hp * 1000. /
			(double)(1000 * 1000 * 1000),
		((double)memoryoperations * sizeof(short)) / kernel_time_mad_hp *
			1000. / (1000. * 1000. * 1000.),
		((double)computations) / ((double)memoryoperations * sizeof(int)),
		kernel_time_mad_int,
		((double)computations) / kernel_time_mad_int * 1000. /
			(double)(1000 * 1000 * 1000),
		((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
			(1000. * 1000. * 1000.));
}

