inline double get_elapsed_time(std::chrono::high_resolution_clock::time_point start) {
    auto end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double>(end - start).count() * 1000.0;
}

template<int iterations>
double benchmark_kernel(double* data, size_t size, unsigned int elements_per_wi, 
                        unsigned int fusion_degree, size_t workgroupsize,
                        int compute_iter, bool use_os_timer, bool block_strided) {
    const size_t compute_grid_size = size / elements_per_wi / fusion_degree / sizeof(double);
    const double seed = 1.0;

    auto ts_start = std::chrono::high_resolution_clock::now();

    #pragma omp parallel for
    for (size_t group_idx = 0; group_idx < compute_grid_size; ++group_idx) {
        size_t base_idx;
        size_t stride;

        if (block_strided) {
            stride = workgroupsize;
            base_idx = group_idx * workgroupsize * elements_per_wi;
        } else {
            stride = compute_grid_size * workgroupsize;
            base_idx = group_idx * elements_per_wi;
        }

        const size_t big_stride = compute_grid_size * workgroupsize * elements_per_wi;

        for (unsigned int k = 0; k < fusion_degree; ++k) {
            for (unsigned int j = 0; j < elements_per_wi; ++j) {
                size_t idx = base_idx + j * stride + k * big_stride;
                double tmp = data[idx];

                for (int i = 0; i < compute_iter; ++i) {
                    tmp = tmp * tmp + seed;
                }

                data[idx] = tmp;
            }

            double sum = 0.0;
            for (unsigned int j = 0; j < elements_per_wi - 1; j += 2) {
                size_t idx0 = base_idx + j * stride + k * big_stride;
                size_t idx1 = base_idx + (j + 1) * stride + k * big_stride;
                sum += data[idx0] * data[idx1];
            }

            if (fabs(sum + 1.0) < 1e-10) {
                size_t idx = base_idx + k * big_stride;
                data[idx] = sum;
            }
        }
    }

    double duration = use_os_timer ? get_elapsed_time(ts_start) : 0.0;
    return duration;
}

